// ── Cache check (Supabase) ──
// TODO: Before calling expensive APIs, check:
// SELECT * FROM agent_cache WHERE cache_key = MD5(city+area+business_type+agent_id)
//   AND updated_at > NOW() - INTERVAL '7 days'
// If cache hit → return cached data immediately
// Implementation: add a Supabase HTTP call before API calls with cache_key lookup

const all = $input.all();
const inputs = $('Parse & Validate Inputs').item.json;

let pricingArticles = [];
let revenueArticles = [];
let mapsData = [];

for (const item of all) {
  const j = item.json;
  if (j?.results && Array.isArray(j.results) && j.results[0]?.place_id !== undefined) {
    mapsData = j.results;
  } else if (j?.organic_results && Array.isArray(j.organic_results)) {
    if (pricingArticles.length === 0) pricingArticles = j.organic_results;
    else revenueArticles = j.organic_results;
  }
}

// ── PARSE AGENT OUTPUTS ──
let a1 = {}; try { a1 = JSON.parse(inputs.a1_competitor_data||'{}')?.outputs||{}; } catch(e){}
let a2 = {}; try { a2 = JSON.parse(inputs.a2_rent_data||'{}')?.outputs||{}; } catch(e){}
let a3 = {}; try { a3 = JSON.parse(inputs.a3_market_data||'{}')?.outputs||{}; } catch(e){}
let a4 = {}; try { a4 = JSON.parse(inputs.a4_cost_data||'{}')?.outputs||{}; } catch(e){}

// ── COMPETITOR RATINGS FROM MAPS ──
const competitors = mapsData.slice(0, 10).map(p => ({
  name:         p.name,
  rating:       p.rating ?? 'N/A',
  reviews:      p.user_ratings_total ?? 0,
  address:      p.formatted_address,
  pricing_tier: p.price_level === 1 ? 'Budget' : p.price_level === 2 ? 'Mid-range' : p.price_level === 3 ? 'Premium' : 'Unknown'
}));

const avgRating = competitors.length > 0
  ? (competitors.reduce((s,c) => s + (parseFloat(c.rating)||0), 0) / competitors.length).toFixed(1)
  : 'N/A';

const totalCompetitorReviews = competitors.reduce((s,c) => s + (c.reviews||0), 0);

// ── ARTICLE SUMMARIES ──
const pricingText = pricingArticles.slice(0,6).map((r,i) =>
  `${i+1}. ${r.title||''}\n   ${(r.snippet||'').slice(0,200)}\n   Source: ${r.displayed_link||''}`
).join('\n\n');

const revenueText = revenueArticles.slice(0,6).map((r,i) =>
  `${i+1}. ${r.title||''}\n   ${(r.snippet||'').slice(0,200)}\n   Source: ${r.displayed_link||''}`
).join('\n\n');

const competitorText = competitors.slice(0,8).map((c,i) =>
  `${i+1}. ${c.name} | Rating: ${c.rating} (${c.reviews} reviews) | Pricing: ${c.pricing_tier}`
).join('\n');

// ── CONTEXT STRINGS FROM PRIOR AGENTS ──
const a1Context = Object.keys(a1).length > 0
  ? `Saturation: ${a1.saturation_level||'N/A'} | Density: ${a1.competitor_density_score||'N/A'}/100\nWithin 500m: ${a1.competitors_within_500m??'N/A'} competitors\nOpportunity Gaps: ${(a1.opportunity_gaps||[]).join('; ')}\nLocality: ${a1.locality_context||'N/A'}`
  : 'Not provided';

const a2Context = Object.keys(a2).length > 0
  ? `Transport Score: ${a2.transport_access_score||'N/A'}/10 | Location Verdict: ${a2.overall_location_verdict||'N/A'}\nAnchor Businesses: ${(a2.anchor_businesses_nearby||[]).map(b=>b.name).join(', ')||'N/A'}\nMajor Anchor Effect: ${a2.major_anchor_effect||'N/A'}\nRent Range: ${a2.rent_range_actual?.min||'N/A'} – ${a2.rent_range_actual?.max||'N/A'}`
  : 'Not provided';

const a3Context = Object.keys(a3).length > 0
  ? `Demand Trend: ${a3.demand_trend||'N/A'} | Market Stage: ${a3.market_maturity_stage||'N/A'}\nGrowth Score: ${a3.growth_score||'N/A'}/100 | ABS Retail: ${a3.abs_data_summary?.trend||'N/A'} (YoY: ${a3.abs_data_summary?.yoy_change_pct||'N/A'}%)\nBest Entry Timing: ${a3.best_entry_timing||'N/A'}\nTarget Segments: ${(a3.target_customer_segments||[]).map(s=>`${s.segment_name} (spend: ${s.spend_profile}, fit: ${s.demand_fit})`).join('; ')||'N/A'}`
  : 'Not provided';

const a4Context = Object.keys(a4).length > 0
  ? `Monthly Operating Cost (A4): ${a4.monthly_operating_cost?.total_monthly||'N/A'} — USE THIS AS EXACT COST BASE\nSetup Cost Recommended: ${a4.setup_cost_estimate?.recommended||'N/A'}\nBurn Rate: ${a4.financial_projections?.burn_rate_monthly||'N/A'} | Runway: ${a4.financial_projections?.runway_months||'N/A'} months\nBreak-even (A4 estimate): ${a4.financial_projections?.break_even_months||'N/A'} months`
  : 'Not provided — estimate costs independently';

// ── DEMAND & PRICING SIGNALS ──
const demandMultiplier = a3.demand_trend === 'Rising'
  ? 'RISING — model faster ramp, higher capacity utilisation by Month 6'
  : a3.demand_trend === 'Falling'
  ? 'FALLING — model conservative ramp, lower utilisation'
  : 'STABLE — model standard ramp curve';

const pricingPowerSignal = a1.saturation_level === 'Low'
  ? 'LOW COMPETITION — pricing power HIGH, premium positioning viable'
  : a1.saturation_level === 'High'
  ? 'HIGH COMPETITION — pricing power LIMITED, must price competitively'
  : 'MEDIUM COMPETITION — mid-range pricing most sustainable';

// ── TRANSPORT SCORE → FOOTFALL ESTIMATE ──
const transportScore = parseFloat(a2.transport_access_score) || 5;
const footfallEstimate = transportScore >= 8 ? '60-80 customers/day potential'
  : transportScore >= 5 ? '30-60 customers/day potential'
  : 'under 30 customers/day — low footfall location';

return [{ json: {
  business_type:              inputs.business_type,
  industry_category:          inputs.industry_category,
  city:                       inputs.city,
  area:                       inputs.area,
  country:                    inputs.country,
  currency:                   inputs.currency,
  avg_ticket_min:             inputs.avg_ticket_min,
  avg_ticket_max:             inputs.avg_ticket_max,
  pricing_positioning:        inputs.pricing_positioning,
  operating_hours:            inputs.operating_hours,
  seating_or_daily_capacity:  inputs.seating_or_daily_capacity,
  business_model:             inputs.business_model,
  email:                      inputs.email,
  competitor_businesses:      competitors,
  avg_competitor_rating:      avgRating,
  total_competitor_reviews:   totalCompetitorReviews,
  pricing_articles_text:      pricingText || 'No pricing data found.',
  revenue_articles_text:      revenueText || 'No revenue benchmark data found.',
  competitor_text:            competitorText || 'No competitor data found.',
  a1_context:                 a1Context,
  a2_context:                 a2Context,
  a3_context:                 a3Context,
  a4_context:                 a4Context,
  demand_multiplier:          demandMultiplier,
  pricing_power_signal:       pricingPowerSignal,
  footfall_estimate:          footfallEstimate,
  transport_score:            transportScore,
  a4_monthly_opex:            a4.monthly_operating_cost?.total_monthly || null,
  a4_setup_cost:              a4.setup_cost_estimate?.recommended || null,
  a3_segments:                a3.target_customer_segments || [],
  data_sources: {
    pricing_articles:  pricingArticles.length,
    revenue_articles:  revenueArticles.length,
    maps_competitors:  competitors.length,
    a1_integrated:     Object.keys(a1).length > 0,
    a2_integrated:     Object.keys(a2).length > 0,
    a3_integrated:     Object.keys(a3).length > 0,
    a4_integrated:     Object.keys(a4).length > 0
  }
}}];

const inputJson = $input.first().json;
const rawText = inputJson.output || inputJson.text || inputJson.response || JSON.stringify(inputJson);
let analysis;
try {
  let cleaned = rawText.trim()
    .replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```\s*$/i,'').trim();
  const start = cleaned.indexOf('{'), end = cleaned.lastIndexOf('}');
  if (start !== -1 && end > start) cleaned = cleaned.slice(start, end+1);
  cleaned = cleaned.replace(/(:\s*)(\d{1,3}(?:,\d{3})+)([,\}\]\s\n])/g,(m,pre,num,post)=>pre+num.replace(/,/g,'')+post);
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = { parse_error: true, raw_response: rawText.slice(0,800), error_message: e.message };
}
const d = $('Process & Merge All Data').item.json;
return [{ json: {
  agent_id:   'A5',
  agent_name: 'Revenue & Profitability (Australian)',
  status:     analysis.parse_error ? 'error' : 'success',
  timestamp:  new Date().toISOString(),
  email:      d.email,
  inputs_used: {
    location:            `${d.area}, ${d.city}, ${d.country}`,
    industry:            d.industry_category,
    avg_ticket:          `${d.currency}${d.avg_ticket_min} – ${d.currency}${d.avg_ticket_max}`,
    pricing_positioning: d.pricing_positioning,
    operating_hours:     d.operating_hours,
    currency:            d.currency,
    transport_score:     d.transport_score,
    footfall_estimate:   d.footfall_estimate
  },
  competitor_businesses: d.competitor_businesses,
  data_sources: d.data_sources,
  outputs: {
    revenue_range:           analysis.revenue_range           || null,
    profitability_score:     analysis.profitability_score     ?? null,
    profitability_reasoning: analysis.profitability_reasoning || null,
    pricing_strategies:      analysis.pricing_strategies      || [],
    revenue_channels:        analysis.revenue_channels        || [],
    customer_volume:         analysis.customer_volume         || {},
    year1_monthly_ramp:      analysis.year1_monthly_ramp      || [],
    sensitivity_analysis:    analysis.sensitivity_analysis    || {},
    break_even_months:       analysis.break_even_months       ?? null,
    break_even_reasoning:    analysis.break_even_reasoning    || null,
    avg_ticket_validation:   analysis.avg_ticket_validation   || {},
    top_revenue_risks:       analysis.top_revenue_risks       || [],
    revenue_growth_levers:   analysis.revenue_growth_levers   || [],
    overall_revenue_verdict: analysis.overall_revenue_verdict || null,
    agent_notes:             analysis.agent_notes             || null
  }
}}];

// ── Output validation ──
const required_keys = Object.keys(analysis).filter(k => !k.startsWith('_') && !k.startsWith('raw'));
if (required_keys.length < 3 || analysis.parse_error) {
  analysis._validation_failed = true;
  analysis._validation_reason = analysis.parse_error ? 'JSON parse error' : 'Insufficient output fields (' + required_keys.length + ')';
}
analysis._validated_at = new Date().toISOString();
analysis._agent_version = 'v2';
